import { useEffect, useState } from "react";
import { supabase } from "../supabaseClient";

const styles = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;700&family=DM+Sans:wght@300;400;500&display=swap');

  :root {
    --bg: #f5f0e8;
    --surface: #faf7f2;
    --border: #e2d9cc;
    --ink: #1a1612;
    --ink-muted: #7a6f63;
    --accent: #c8441a;
  }

  .page-root {
    min-height: 100vh;
    background: var(--bg);
    font-family: 'DM Sans', sans-serif;
    color: var(--ink);
    padding: 80px 24px 80px;
  }

  .page-inner {
    max-width: 680px;
    margin: 0 auto;
  }

  .page-header {
    display: flex;
    align-items: baseline;
    gap: 12px;
    margin-bottom: 24px;
    padding-bottom: 20px;
    border-bottom: 1.5px solid var(--border);
  }

  .page-header h2 {
    font-family: 'Playfair Display', serif;
    font-size: 2.2rem;
    font-weight: 700;
    letter-spacing: -0.02em;
    line-height: 1;
    color: var(--ink);
  }

  .page-header .dot {
    width: 8px;
    height: 8px;
    border-radius: 50%;
    background: var(--accent);
    flex-shrink: 0;
    margin-bottom: 4px;
  }

  .section-label {
    font-size: 0.75rem;
    font-weight: 500;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    color: var(--ink-muted);
    margin: 32px 0 16px;
  }

  .list-card {
    background: var(--surface);
    border: 1.5px solid var(--border);
    border-radius: 10px;
    padding: 16px 20px;
    margin-bottom: 12px;
    cursor: pointer;
    transition: transform 200ms ease, box-shadow 200ms ease, border-color 200ms ease;
    display: flex;
    align-items: center;
    gap: 12px;
    font-size: 1.05rem;
    font-weight: 500;
  }

  .list-card:hover {
    border-color: #c8b9a8;
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(26,22,18,0.05);
  }

  .empty-msg {
    color: var(--ink-muted);
    font-size: 0.9rem;
    font-style: italic;
  }
`;

export default function Followers() {
  const [followers, setFollowers] = useState([]);

  useEffect(() => {
    fetchFollowers();
  }, []);

  const fetchFollowers = async () => {
    const { data: userData } = await supabase.auth.getUser();
    const user = userData.user;

    if (!user) return;

    const { data } = await supabase
      .from("follows")
      .select("*")
      .eq("following_id", user.id); // 🔥 IMPORTANT

    const ids = data.map((f) => f.follower_id);

    const { data: profiles } = await supabase
      .from("profiles")
      .select("id, name")
      .in("id", ids);

    const merged = data.map((f) => ({
      ...f,
      profiles: profiles.find((p) => p.id === f.follower_id),
    }));

    setFollowers(merged);
  };

  return (
    <>
      <style>{styles}</style>
      <div className="page-root">
        <div className="page-inner">
          <div className="page-header">
            <h2>Followers</h2>
            <div className="dot" />
          </div>

          <div className="section-label">Your Followers</div>

          {followers.length === 0 ? (
            <p className="empty-msg">No followers</p>
          ) : (
            followers.map((f, i) => (
              <div key={i} className="list-card">
                👤 {f.profiles?.name || "User"}
              </div>
            ))
          )}
        </div>
      </div>
    </>
  );
}
